	want := Bead{ID: "ddx-arch-1", Title: "archived item", Status: StatusClosed, IssueType: "task", Priority: 2}
	require.NoError(t, s.WriteAll([]Bead{want}))
	got, err = s.ReadAll(testCtx())
	require.NoError(t, err)
	require.Len(t, got, 1)

