	attemptID := time.Now().UTC().Format("20060102T150405") + "-pmcblk1"
	res := &ExecuteBeadResult{
		BeadID:       b.ID,
		BaseRev:      r.baseSHA,
		ResultRev:    resultSHA,
		ExecutionDir: filepath.Join(".ddx", "executions", attemptID),
		Outcome:      ExecuteBeadOutcomeTaskSucceeded,
		Status:       ExecuteBeadStatusSuccess,
		ExitCode:     0,
